using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly MLContext _mlContext;
    private EvaluationMetricsResponse? _metrics;

    public ModelTrainingService(IWebHostEnvironment env)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        _mlContext = new MLContext(seed: 42);
    }

    public EvaluationMetricsResponse? Metrics => _metrics;

    /// <summary>Labels in the order matching the Score array indices.</summary>
    public string[] Labels { get; private set; } = [];

    public string TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // With a small dataset, use all data for training and evaluate on the same set.
        // In production, use TrainTestSplit with a larger dataset.
        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(data);

        // Extract label names in Score-array order from the model schema
        var predictions = model.Transform(data);
        var scoreColumn = predictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _metrics = new EvaluationMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
        };

        _mlContext.Model.Save(model, data.Schema, _modelPath);

        return _modelPath;
    }
}

